package com.google.gson.internal.bind;

import static org.junit.jupiter.api.Assertions.*;
import static org.mockito.Mockito.*;

import com.google.gson.JsonPrimitive;
import com.google.gson.stream.JsonToken;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;

import java.lang.reflect.Field;
import java.lang.reflect.Method;

public class JsonTreeReaderTest {

  private JsonTreeReader reader;

  @BeforeEach
  public void setUp() throws Exception {
    // Create a dummy JsonPrimitive with boolean true
    JsonPrimitive truePrimitive = new JsonPrimitive(true);

    // Create instance with a dummy JsonElement (null for now)
    reader = new JsonTreeReader(null);

    // Use reflection to set private fields stack, stackSize, pathIndices
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = new Object[32];
    stackArray[0] = truePrimitive;
    stackField.set(reader, stackArray);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 1);

    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndicesArray = new int[32];
    pathIndicesArray[0] = 0;
    pathIndicesField.set(reader, pathIndicesArray);

    // Mock expect method to do nothing when called with JsonToken.BOOLEAN
    Method expectMethod = JsonTreeReader.class.getDeclaredMethod("expect", JsonToken.class);
    expectMethod.setAccessible(true);
    // We can't mock private method easily without a mocking framework that supports it,
    // so we will replace it by a spy and override expect, but since JsonTreeReader is final,
    // we cannot spy it. Instead, we will call expect via reflection in nextBoolean and it will run.
    // So we need to set stack top to a JsonPrimitive boolean for expect to pass.
  }

  @Test
  public void testNextBooleanReturnsTrueAndIncrementsPathIndex() throws Exception {
    // Initial pathIndices[0] = 0
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = (int[]) pathIndicesField.get(reader);
    assertEquals(0, pathIndices[0]);

    // Call nextBoolean
    boolean result = reader.nextBoolean();

    assertTrue(result);

    // Verify pathIndices[0] incremented by 1
    assertEquals(1, pathIndices[0]);

    // Verify stackSize remains unchanged
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    int stackSize = stackSizeField.getInt(reader);
    assertEquals(0, stackSize - 1 + 1); // stackSize is 1

    // Verify stack top was popped (stackSize decreased by 1)
    // Actually nextBoolean pops the stack, so stackSize should be 0 now
    assertEquals(0, stackSizeField.getInt(reader));
  }

  @Test
  public void testNextBooleanWithStackSizeZeroDoesNotIncrementPathIndex() throws Exception {
    // Setup stack with one boolean JsonPrimitive true
    JsonPrimitive truePrimitive = new JsonPrimitive(true);
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = new Object[32];
    stackArray[0] = truePrimitive;
    stackField.set(reader, stackArray);

    // Set stackSize to 1
    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 1);

    // Set pathIndices[0] to 0
    Field pathIndicesField = JsonTreeReader.class.getDeclaredField("pathIndices");
    pathIndicesField.setAccessible(true);
    int[] pathIndices = new int[32];
    pathIndices[0] = 0;
    pathIndicesField.set(reader, pathIndices);

    // Call nextBoolean once - pops the stack, stackSize becomes 0
    boolean result = reader.nextBoolean();
    assertTrue(result);

    // Now call nextBoolean again, but stackSize is 0, so no increment to pathIndices
    // We need to push a boolean JsonPrimitive again to stack for next call
    stackArray[0] = new JsonPrimitive(false);
    stackField.set(reader, stackArray);
    stackSizeField.setInt(reader, 1);
    pathIndices[0] = 5;

    boolean result2 = reader.nextBoolean();
    assertFalse(result2);

    // pathIndices[0] should be incremented since stackSize > 0 before pop
    assertEquals(6, pathIndices[0]);
  }

  @Test
  public void testNextBooleanThrowsIfTopStackIsNotBooleanPrimitive() throws Exception {
    // Setup stack with a JsonPrimitive that is not boolean (string)
    JsonPrimitive stringPrimitive = new JsonPrimitive("notBoolean");
    Field stackField = JsonTreeReader.class.getDeclaredField("stack");
    stackField.setAccessible(true);
    Object[] stackArray = new Object[32];
    stackArray[0] = stringPrimitive;
    stackField.set(reader, stackArray);

    Field stackSizeField = JsonTreeReader.class.getDeclaredField("stackSize");
    stackSizeField.setAccessible(true);
    stackSizeField.setInt(reader, 1);

    // nextBoolean should throw ClassCastException when casting to JsonPrimitive and calling getAsBoolean
    assertThrows(ClassCastException.class, () -> {
      reader.nextBoolean();
    });
  }
}
